/*
 * reconstruct-weights-gpu.cu: GPU kernel for on-device weight decompression
 * Reconstructs full-precision weights from quantized spectral components in <100ms
 *
 * Input: U [d_out × 3], Σ [3], V^T [3 × d_in] (quantized, delta-encoded)
 * Output: W [d_out × d_in] (full precision, FP32)
 *
 * Kernel: W[i][j] = Σ_k U[i][k] * σ[k] * V[j][k]
 * Dequantization: δ_q8 → dequantize via min/max → float
 * Delta decode: δ_q8[i] -> accumulate differences to recover original values
 */

#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdint.h>

// Block size for tiling (must divide d_out and d_in evenly)
#define BLOCK_SIZE 16
#define NUM_COMPONENTS 3

/*
 * Dequantize uint8 value back to float using min/max normalization.
 * q8 is in [0, 255]; normalized to [min_val, max_val]
 */
__device__ float dequantize_uint8(uint8_t q8, float min_val, float max_val) {
    float normalized = (float)q8 / 255.0f;
    return min_val + normalized * (max_val - min_val);
}

/*
 * Delta-decode: given delta-encoded values, reconstruct original.
 * deltas[0] is the first value; deltas[i] is the difference from deltas[i-1]
 */
__device__ float delta_decode(const uint8_t* deltas, int idx, float first_val) {
    if (idx == 0) return first_val;

    float current = first_val;
    for (int i = 1; i <= idx; i++) {
        // Treat uint8 as signed int8 (two's complement)
        int8_t delta = (int8_t)deltas[i];
        current += (float)delta / 255.0f;
    }
    return current;
}

/*
 * Kernel: reconstruct_weights_spectral
 *
 * Per-thread: compute W[i][j] = Σ_k U[i][k] * σ[k] * V[j][k]
 *
 * Thread block: [BLOCK_SIZE × BLOCK_SIZE]
 * Grid: covers all (d_out, d_in) tiles
 */
__global__ void reconstruct_weights_spectral(
    const uint8_t* U_q8,           // [d_out × 3] quantized deltas
    const uint8_t* sigma_q8,       // [3] quantized deltas
    const uint8_t* Vt_q8,          // [3 × d_in] quantized deltas
    float* W_out,                  // [d_out × d_in] output
    int d_out, int d_in,
    float U_min, float U_max,      // Dequantization range for U
    float sigma_min, float sigma_max,  // Dequantization range for sigma
    float V_min, float V_max       // Dequantization range for V
) {
    int i = blockIdx.y * blockDim.y + threadIdx.y;  // row (d_out dimension)
    int j = blockIdx.x * blockDim.x + threadIdx.x;  // col (d_in dimension)

    if (i >= d_out || j >= d_in) return;

    // Accumulator for W[i][j]
    float w_ij = 0.0f;

    // Sum over k=0,1,2 (NUM_COMPONENTS)
    for (int k = 0; k < NUM_COMPONENTS; k++) {
        // Dequantize U[i][k]
        int u_idx = i * NUM_COMPONENTS + k;
        float u_ik = dequantize_uint8(U_q8[u_idx], U_min, U_max);

        // Dequantize σ[k]
        float sigma_k = dequantize_uint8(sigma_q8[k], sigma_min, sigma_max);

        // Dequantize V[k][j]
        int v_idx = k * d_in + j;
        float v_kj = dequantize_uint8(Vt_q8[v_idx], V_min, V_max);

        // Accumulate: W[i][j] += U[i][k] * σ[k] * V[k][j]
        w_ij += u_ik * sigma_k * v_kj;
    }

    // Write result
    W_out[i * d_in + j] = w_ij;
}

/*
 * Kernel variant with delta decoding
 * If weights were delta-encoded, decode first before reconstruction
 */
__global__ void reconstruct_weights_with_delta(
    const uint8_t* U_delta,        // [d_out × 3] delta-encoded deltas
    const uint8_t* sigma_delta,    // [3] delta-encoded deltas
    const uint8_t* Vt_delta,       // [3 × d_in] delta-encoded deltas
    float* W_out,                  // [d_out × d_in] output
    int d_out, int d_in,
    float U_min, float U_max,
    float sigma_min, float sigma_max,
    float V_min, float V_max
) {
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;

    if (i >= d_out || j >= d_in) return;

    float w_ij = 0.0f;

    for (int k = 0; k < NUM_COMPONENTS; k++) {
        // Delta-decode U[i][k]
        int u_idx = i * NUM_COMPONENTS + k;
        float u_ik_q8 = delta_decode(U_delta, u_idx, (float)U_delta[0]);
        float u_ik = dequantize_uint8((uint8_t)u_ik_q8, U_min, U_max);

        // Delta-decode σ[k]
        float sigma_k_q8 = delta_decode(sigma_delta, k, (float)sigma_delta[0]);
        float sigma_k = dequantize_uint8((uint8_t)sigma_k_q8, sigma_min, sigma_max);

        // Delta-decode V[k][j]
        int v_idx = k * d_in + j;
        float v_kj_q8 = delta_decode(Vt_delta, v_idx, (float)Vt_delta[0]);
        float v_kj = dequantize_uint8((uint8_t)v_kj_q8, V_min, V_max);

        w_ij += u_ik * sigma_k * v_kj;
    }

    W_out[i * d_in + j] = w_ij;
}

/*
 * Host wrapper: reconstruct_weights_host
 *
 * Allocates GPU memory, copies data, launches kernel, copies back result
 * Returns: 0 on success, non-zero on CUDA error
 */
extern "C" {

typedef struct {
    float* d_W_out;           // Device output weight matrix
    uint8_t* d_U_q8;
    uint8_t* d_sigma_q8;
    uint8_t* d_Vt_q8;
} gpu_workspace_t;

int reconstruct_weights_host(
    const uint8_t* h_U_q8,
    const uint8_t* h_sigma_q8,
    const uint8_t* h_Vt_q8,
    float* h_W_out,
    int d_out, int d_in,
    float U_min, float U_max,
    float sigma_min, float sigma_max,
    float V_min, float V_max
) {
    // Allocate device memory
    uint8_t* d_U_q8 = nullptr;
    uint8_t* d_sigma_q8 = nullptr;
    uint8_t* d_Vt_q8 = nullptr;
    float* d_W_out = nullptr;

    size_t u_size = d_out * NUM_COMPONENTS * sizeof(uint8_t);
    size_t sigma_size = NUM_COMPONENTS * sizeof(uint8_t);
    size_t vt_size = NUM_COMPONENTS * d_in * sizeof(uint8_t);
    size_t w_size = d_out * d_in * sizeof(float);

    cudaMalloc(&d_U_q8, u_size);
    cudaMalloc(&d_sigma_q8, sigma_size);
    cudaMalloc(&d_Vt_q8, vt_size);
    cudaMalloc(&d_W_out, w_size);

    // Check allocation
    if (!d_U_q8 || !d_sigma_q8 || !d_Vt_q8 || !d_W_out) {
        cudaFree(d_U_q8);
        cudaFree(d_sigma_q8);
        cudaFree(d_Vt_q8);
        cudaFree(d_W_out);
        return 1;
    }

    // Copy data to device
    cudaMemcpy(d_U_q8, h_U_q8, u_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_sigma_q8, h_sigma_q8, sigma_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_Vt_q8, h_Vt_q8, vt_size, cudaMemcpyHostToDevice);

    // Launch kernel
    dim3 block_size(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid_size((d_in + BLOCK_SIZE - 1) / BLOCK_SIZE, (d_out + BLOCK_SIZE - 1) / BLOCK_SIZE);

    reconstruct_weights_spectral<<<grid_size, block_size>>>(
        d_U_q8, d_sigma_q8, d_Vt_q8, d_W_out,
        d_out, d_in,
        U_min, U_max, sigma_min, sigma_max, V_min, V_max
    );

    // Check for kernel errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        cudaFree(d_U_q8);
        cudaFree(d_sigma_q8);
        cudaFree(d_Vt_q8);
        cudaFree(d_W_out);
        return 2;
    }

    // Copy result back to host
    cudaMemcpy(h_W_out, d_W_out, w_size, cudaMemcpyDeviceToHost);

    // Synchronize and check
    cudaDeviceSynchronize();

    // Cleanup
    cudaFree(d_U_q8);
    cudaFree(d_sigma_q8);
    cudaFree(d_Vt_q8);
    cudaFree(d_W_out);

    return 0;
}

}  // extern "C"
